  'marketing.standard.spec.wedding.receptionTime': 'Reception start time. Format: HH:MM. Always quote.',
  'marketing.standard.spec.wedding.gettingReadyLocation': 'Where the couple is getting ready, such as hotel or home.',
  'marketing.standard.spec.wedding.gettingReadyTime': 'Getting-ready start time. Always quote.',
